import concurrent.futures

def worker(item, counter):
    print(item)
    counter.increment()

def main():
    import threading
    counter = threading.ThreadCounter()
    with concurrent.futures.ThreadPoolExecutor() as executor:
        futures = []
        for i in range(5):
            futures.append(executor.submit(worker, i, counter))
        for i in range(5):
            futures.append(executor.submit(worker, None, counter))
        for i in range(3):
            futures.append(executor.submit(worker, i, counter))
    print(counter.value)

